package com.hiliving.content.news;import java.time.Instant;public record NewsResponse(Long id,String title,String slug,String summary,String content,String thumbnailUrl,boolean published,Instant publishedAt,int sortOrder,Instant createdAt,Instant updatedAt){static NewsResponse from(NewsEntity n){return new NewsResponse(n.getId(),n.getTitle(),n.getSlug(),n.getSummary(),n.getContent(),n.getThumbnailUrl(),n.isPublished(),n.getPublishedAt(),n.getDisplayOrder(),n.getCreatedAt(),n.getUpdatedAt());}}
